class Flag {
    boolean stop = false;
}
Flag f = new Flag();
Thread t = new Thread(() -> {
    while (!f.stop) {
        // busy loop
    }
    System.out.println("stopped");
});
t.start();
Thread.sleep(100);
f.stop = true;

class Flag {
    volatile boolean stop = false;
}
Flag f = new Flag();
Thread t = new Thread(() -> {
    while (!f.stop) {}
    System.out.println("stopped");
});
t.start();
Thread.sleep(100);
f.stop = true;

class Singleton {
    private static Singleton instance; // volatile degil
    private Singleton() {}
    static Singleton get() {
        if (instance == null) {
            synchronized (Singleton.class) {
                if (instance == null) {
                    instance = new Singleton();
                }
            }
        }
        return instance;
    }
}

class Counter {
    private int value = 0;
    synchronized void inc() { value++; }
    synchronized int get() { return value; }
}

